    for (auto word : words) // We normally pass string_view by value, so we'll use auto here
        std::cout << word << ' ';

    std::cout << '\n';

    return 0;
}In this example, we have astd::vectorcontainingstd::string_viewobjects. Sincestd::string_viewis normally passed by value, usingautoseems appropriate.But consider what happens ifwordsis later updated to an array ofstd::stringinstead.#include <iostream>
#include <string>
#include <vector>

int main()
{
